 }
+
+var spawnDaemon = func(bin string, args []string, logFile *os.File) error {
+	proc := exec.Command(bin, args...)
+	proc.Stdout = logFile
+	proc.Stderr = logFile
+	proc.Stdin = nil
+	proc.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
+	return proc.Start()
+}
